(() => {
    interface Tiny {
      x: string;
    }
    interface Medium {
      x: string;
      y: number;
    }
    interface Large {
      x: string;
      y: number;
      z: boolean;
    }
    return {build: () => createValidate<Tiny | Medium | Large>(), buildErrors: () => noErrs(createGetValidationErrors<Tiny | Medium | Large>())};
  })()

(() => {
    interface Tiny {
      x: string;
    }
    interface Medium {
      x: string;
      y: number;
    }
    interface Large {
      x: string;
      y: number;
      z: boolean;
    }
    return {
      build: () => {
        const check = typia.createIs<Tiny | Medium | Large>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<Tiny | Medium | Large>();
        return (v) => val(v).success;
      },
    };
  })()
